import{_ as d,c as o,o as c,aj as a}from"./chunks/framework.VtnL2jmu.js";const g=JSON.parse('{"title":"fd：更现代的 find","description":"","frontmatter":{},"headers":[],"relativePath":"Linux/fd：更现代的 find.md","filePath":"Linux/fd：更现代的 find.md"}'),i={name:"Linux/fd：更现代的 find.md"};function s(n,e,t,l,r,f){return c(),o("div",null,[...e[0]||(e[0]=[a(`<h1 id="fd-更现代的-find" tabindex="-1">fd：更现代的 <code>find</code> <a class="header-anchor" href="#fd-更现代的-find" aria-label="Permalink to “fd：更现代的 find”">​</a></h1><p>有了 <code>bat</code> 替代 <code>cat</code>，你还需要 <code>fd</code> 替代 <code>find</code>。</p><ul><li><strong>优势</strong>：默认忽略 <code>.git</code> 和 <code>target</code> 目录（这在 Maven 项目里太重要了！），搜索速度比原生 <code>find</code> 快得多。</li><li><strong>联动</strong>：它和 <code>fzf</code> 是天生一对，配置 <code>fzf</code> 使用 <code>fd</code> 作为后台，搜索文件时就再也不会搜出一堆 <code>target/classes</code> 下的垃圾文件了。</li><li><strong>安装</strong>：<code>sudo apt install fd-find</code> (别名设置参考 bat，也是 <code>alias fd=&#39;fdfind&#39;</code>)。</li></ul><p>以下是 <code>fd</code> 值得你深入配置和使用的几个核心维度：</p><h3 id="_1-为什么它是-开发者友好-的" tabindex="-1">1. 为什么它是“开发者友好”的？ <a class="header-anchor" href="#_1-为什么它是-开发者友好-的" aria-label="Permalink to “1. 为什么它是“开发者友好”的？”">​</a></h3><p>原生的 <code>find</code> 默认会翻遍每一个角落，但在我们的日常开发中，很多目录是<strong>完全不需要搜索</strong>的。</p><ul><li><strong>智能忽略</strong>：<code>fd</code> 默认会自动忽略 <code>.gitignore</code> 里的内容，并且自动跳过隐藏文件夹（如 <code>.git</code>）和特定的编译目录（如 <code>target/</code>）。</li><li><strong>速度优势</strong>：它是用 Rust 写的，支持并行搜索。在像 <code>tour-tide-plus</code> 这样拥有大量依赖和源码的项目中，它的响应几乎是瞬间的。</li><li><strong>彩色输出</strong>：它会根据文件类型自动上色（就像 <code>ls</code> 那样），一眼就能分清文件夹、脚本和配置文件。</li></ul><hr><h3 id="_2-核心用法速览" tabindex="-1">2. 核心用法速览 <a class="header-anchor" href="#_2-核心用法速览" aria-label="Permalink to “2. 核心用法速览”">​</a></h3><p>安装好并设置完别名 <code>alias fd=&#39;fdfind&#39;</code> 后，你可以尝试这些命令：</p><ul><li><p><strong>最简搜索</strong>：<code>fd user</code></p><p>（搜索所有文件名包含 &quot;user&quot; 的文件，不需要像 <code>find</code> 那样写 <code>-name &quot;*user*&quot;</code>）</p></li><li><p><strong>按扩展名搜</strong>：<code>fd -e java</code></p><p>（只找 Java 文件）</p></li><li><p><strong>执行命令（类似 -exec）</strong>：<code>fd -e sql -x mycli &lt;</code></p><p>（找到所有 SQL 文件并批量用 <code>mycli</code> 处理，语法比 <code>find</code> 的 <code>-exec ... {} \\;</code> 简洁得多）</p></li><li><p><strong>包含隐藏文件</strong>：<code>fd -H config</code></p><p>（如果你想搜 <code>.env</code> 或者 <code>.rc</code> 这种隐藏文件，加个 <code>-H</code> 即可）</p></li></ul><hr><h3 id="_3-【重点】与-fzf-的-王炸-联动" tabindex="-1">3. 【重点】与 fzf 的“王炸”联动 <a class="header-anchor" href="#_3-【重点】与-fzf-的-王炸-联动" aria-label="Permalink to “3. 【重点】与 fzf 的“王炸”联动”">​</a></h3><p>这是最能提升体验的一步。默认情况下，<code>fzf</code> 搜索文件时调用的是系统的 <code>find</code>，会把一堆 <code>.git</code> 或 <code>node_modules</code> 里的杂质搜出来。</p><p>你可以通过设置环境变量，让 <code>fzf</code> 底层改用 <code>fd</code>：</p><ol><li><p><strong>打开配置</strong>：<code>vim ~/.rc</code></p></li><li><p><strong>加入以下配置</strong>：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span># 让 fzf 默认使用 fd 进行搜索（忽略 gitignore 里的内容）</span></span>
<span class="line"><span>export FZF_DEFAULT_COMMAND=&#39;fd --type f&#39;</span></span>
<span class="line"><span># 当你在终端按 Ctrl+T 时，也使用 fd</span></span>
<span class="line"><span>export FZF_CTRL_T_COMMAND=&quot;$FZF_DEFAULT_COMMAND&quot;</span></span></code></pre></div></li><li><p><strong>生效</strong>：<code>source ~/.rc</code></p></li></ol><p><strong>效果：</strong> 之后你按 <code>Ctrl+T</code> 找文件时，你会发现列表非常清爽，搜出来的全是你想改的代码，再也没有 <code>target/classes</code> 下面的那些干扰项了。</p><hr><h3 id="_4-关于安装的小细节" tabindex="-1">4. 关于安装的小细节 <a class="header-anchor" href="#_4-关于安装的小细节" aria-label="Permalink to “4. 关于安装的小细节”">​</a></h3><p>在 Ubuntu/Debian 上，包名是 <code>fd-find</code>，执行命令是 <code>fdfind</code>。</p><p>为了用起来更顺手，一定要在 <code>~/.rc</code> 里加这一行：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>alias fd=&#39;fdfind&#39;</span></span></code></pre></div>`,22)])])}const h=d(i,[["render",s]]);export{g as __pageData,h as default};
